window.__QUIZ_DATA__=[{"id":"objective>Commerce>2018>1","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Activities which facilitate commerce include","images":[],"options":{"A":"engaging youths in environmental sanitation.","B":"funding political campaigns.","C":"providing recreational facilities in communities.","D":"improving road networks."},"answer":"D","explanation":"Activities that facilitate commerce are those that make the process of buying and selling goods and services easier. This includes improving infrastructure such as road networks which makes transportation of goods easier.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>2","subject":"Commerce","year":"2018","type":"Objective","topic":"STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS","question":"A document through which invitation is extended to the public to subscribe to shares is","images":[],"options":{"A":"article of association.","B":"prospectus.","C":"memorandum of association.","D":"quotation."},"answer":"B","explanation":"A prospectus is a legal document issued by companies that are offering securities for sale. It contains details about the company, its operations, and the securities being offered.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>3","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"One example of a product of the construction industry is","images":[],"options":{"A":"chair.","B":"bag of cement.","C":"piece of cloth.","D":"television"},"answer":"B","explanation":"The construction industry involves the building and assembly of infrastructure, and cement is a key material used in this process.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>4","subject":"Commerce","year":"2018","type":"Objective","topic":"BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION","question":"A person authorized to sell the property of a company in a winding up is","images":[],"options":{"A":"an auctioneer.","B":"an agent.","C":"a liquidator.","D":"a bailee"},"answer":"C","explanation":"In the context of a company winding up, a liquidator is the person who is authorized to sell the property of the company. A liquidator is appointed when a company goes into liquidation or winding up. Their main role is to sell the company's assets, settle the claims of creditors, and distribute any remaining assets to the shareholders. An auctioneer, agent, and bailee do not have the same level of authority or responsibility in a company winding up.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>5","subject":"Commerce","year":"2018","type":"Objective","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"The space marked A represents","images":["data:image/png;base64,"],"options":{"A":"trading.","B":"industry.","C":"occupation.","D":"advertising."},"answer":"C","explanation":"The space represent occupation or division of production.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>6","subject":"Commerce","year":"2018","type":"Objective","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"The space marked X represents","images":["data:image/png;base64,"],"options":{"A":"industry.","B":"foreign trade.","C":"home trade.","D":"production."},"answer":"A","explanation":"The space represent industry based on division of occupation.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>7","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA","question":"What does the space marked M represent?","images":["data:image/png;base64,"],"options":{"A":"quarrying","B":"manufacturing","C":"agriculture","D":"trade"},"answer":"D","explanation":"The space represent trade based on division of commerce.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>8","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA","question":"The purchase and sale of goods over electronic system is","images":[],"options":{"A":"E-payment","B":"E-commerce","C":"E-mail","D":"E-transfer"},"answer":"B","explanation":"The purchase and sale of goods over an electronic system is referred to as E-commerce. E-commerce, or electronic commerce, refers to transactions conducted via the internet. Every time individuals and companies are buying or selling products and services online they're engaging in e-commerce. The term e-commerce also encompasses other activities including online auctions, internet banking, payment gateways, and online ticketing.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>9","subject":"Commerce","year":"2018","type":"Objective","topic":"BUSINESS UNIT: SOLE PROPRIETORSHIP : ADVANTAGES & DISADVANTAGES","question":"One disadvantage of a sole proprietorship is","images":[],"options":{"A":"quick decision making","B":"unlimited liability","C":"pride of ownership","D":"unlimited sources of capital"},"answer":"B","explanation":"One disadvantage of a sole proprietorship is unlimited liability. In a sole proprietorship, the owner is personally liable for all the debts and obligations of the business. This means that if the business incurs a debt or is sued, the owner's personal assets can be used to satisfy these obligations. Quick decision making, pride of ownership, and unlimited sources of capital are generally considered advantages, not disadvantages, of a sole proprietorship.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>10","subject":"Commerce","year":"2018","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"Which of the following is a source of short-term finance to a business","images":[],"options":{"A":"Hire purchase","B":"Overdraft","C":"Lease","D":"Debenture"},"answer":"B","explanation":"An overdraft is a type of short-term finance where a bank allows a company to withdraw more money than it has in its account, up to a certain limit. This is a form of short-term finance because it is typically meant to cover a company's immediate financial needs and is expected to be paid back quickly. The other options, such as hire purchase, lease, and debenture, are typically forms of long-term finance.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>11","subject":"Commerce","year":"2018","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"The portion of share capital which the company has asked shareholders to pay is","images":[],"options":{"A":"called-up capital","B":"authorized capital","C":"paid-up capital","D":"unpaid capital"},"answer":"A","explanation":"Called-up capital is the portion of share capital that a company has asked its shareholders to pay. Authorized capital is the maximum amount of share capital that a company is allowed to issue, while paid-up capital is the amount of money a company has received from shareholders in exchange for shares. Unpaid capital is the part of the issued capital of a company which has not yet been paid by the shareholders.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>12","subject":"Commerce","year":"2018","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Multilateral trade is carried out","images":[],"options":{"A":"between two countries only","B":"within many countries","C":"among many countries","D":"between neighbouring countries only"},"answer":"C","explanation":"Multilateral trade is trade that is conducted among many countries, without discrimination. It is carried out through international agreements, where all signatories treat each other equally. This is different from bilateral trade, which is trade between two countries, and does not necessarily involve many countries or neighboring countries only.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>13","subject":"Commerce","year":"2018","type":"Objective","topic":"TRADE ASSOCIATION : CHAMBER OF COMMERCE","question":"An association of businesses engaged in both trade and industry is a","images":[],"options":{"A":"co-operative society","B":"trade union","C":"trust fund","D":"chamber of commerce"},"answer":"D","explanation":"A chamber of commerce is a form of business network, for example, a local organization of businesses whose goal is to further the interests of businesses. Business owners in towns and cities form these local societies to advocate on behalf of the business community.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>14","subject":"Commerce","year":"2018","type":"Objective","topic":"STOCK EXCHANGE : TYPES OF SECURITIES","question":"Which of the following statements is true of a debenture?","images":[],"options":{"A":"Its holders receive interest","B":"It forms part of a company's authorized capital","C":"Its holders are co-owners of the company","D":"Its holders control the company"},"answer":"A","explanation":"A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. The holders of debentures are paid interest for their investment.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>15","subject":"Commerce","year":"2018","type":"Objective","topic":"ELEMENT OF MARKETING : THE MARKETING CONCEPT","question":"The path through which a product moves from the manufacturer to the consumer is a","images":[],"options":{"A":"channel of communication","B":"line of production","C":"means of transportation","D":"channel of distribution"},"answer":"D","explanation":"The path through which a product moves from the manufacturer to the consumer is known as the channel of distribution. It includes all the entities involved in getting the product from the producer to the consumer, including wholesalers, retailers, and distributors.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>16","subject":"Commerce","year":"2018","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER","question":"If the share stock of Ali Ltd is #40,000, cost of goods sold is #48,000 and closing stock is #24,000, its rate of turnover will be","images":[],"options":{"A":"1.2 times","B":"1.5 times","C":"2.0 times","D":"7.5 times"},"answer":"C","explanation":"The rate of turnover is calculated by dividing the cost of goods sold by the average inventory. In this case, the average inventory is not given, but we can assume that the closing stock is the average inventory. Therefore, the rate of turnover is 48000/24000 = 2.0 times.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>17","subject":"Commerce","year":"2018","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"A business which requires a certificate of trading in order to commence operation is a","images":[],"options":{"A":"co-operative society","B":"private company","C":"sole proprietorship","D":"public company"},"answer":"D","explanation":"A public company is a type of business that requires a certificate of trading in order to commence operation. This is because public companies are allowed to sell shares to the public and are therefore subject to more regulations than other types of businesses.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>18","subject":"Commerce","year":"2018","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Exchange of goods in international market which does not involve the use of money is","images":[],"options":{"A":"barter trade","B":"entrepot trade","C":"counter trade","D":"bilateral trade"},"answer":"C","explanation":"Counter trade is a form of international trade in which goods or services are exchanged for other goods or services rather than the use of hard currency.    Countries that engage in countertrade have limited foreign exchange or credit facilities, and it is most common in developing countries.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>19","subject":"Commerce","year":"2018","type":"Objective","topic":"TRADE ASSOCIATION : CHAMBER OF COMMERCE","question":"Which of the following features is not associated with a chamber of commerce? It is","images":[],"options":{"A":"democratically administered","B":"an independent association","C":"open only to entrepreneurs","D":"a voluntary association"},"answer":"C","explanation":"A chamber of commerce is a local association to promote and protect the interests of the business community in a particular place. It is democratically administered, an independent association, and a voluntary association. However, it is not open only to entrepreneurs. It is open to all businesses, big or small, entrepreneur or corporation.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>20","subject":"Commerce","year":"2018","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF TRADE","question":"The reason for sending a proforma invoice to a potential customer is that it is","images":[],"options":{"A":"an indication of the seller's willingness to grant credit","B":"a polite way of telling the customer to return the goods","C":"an invitation to the buyer to buy on hire purchase","D":"a polite way of refusing to sell on credit"},"answer":"A","explanation":"A proforma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. It is an indication of the seller's willingness to sell the goods or services to the buyer. It is not a polite way of telling the customer to return the goods, an invitation to the buyer to buy on hire purchase, or a polite way of refusing to sell on credit.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>21","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TYPES","question":"The insurance policy taken to cover dishonesty of accounts personnel of an organization is","images":[],"options":{"A":"employees's liability","B":"fidelity guarantee","C":"life endowment","D":"marine insurance"},"answer":"B","explanation":"Fidelity guarantee insurance is a type of insurance policy that covers businesses for the loss of money or property sustained as a direct result of acts of fraud, theft or dishonesty by an employee in the course of employment. It is not employees's liability, life endowment, or marine insurance.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>22","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION","question":"Which of the following document is used when goods are being sent by a common carrier?","images":[],"options":{"A":"Delivery note","B":"Consignment note","C":"Advice note","D":"Credit note"},"answer":"B","explanation":"A consignment note is a document that accompanies goods being transported by a common carrier and describes the goods, the details of the consignor and consignee. It serves as a proof that the carrier has received the goods and has a contract from the consignor to carry them. The other options are not specifically used for goods being sent by a common carrier.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>23","subject":"Commerce","year":"2018","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"A put option in the stock exchange is an option","images":[],"options":{"A":"to sell","B":"not to sell","C":"to buy","D":"not to buy"},"answer":"A","explanation":"A put option in the stock exchange is an option to sell a specified amount of an underlying security at a specified price within a specified time. This is a financial contract between the buyer and the seller of the put option. The buyer of the put option has the right, but not the obligation, to sell an agreed quantity of a particular commodity or financial instrument (the underlying) to the seller of the option at a certain time for a certain price (the strike price).","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>24","subject":"Commerce","year":"2018","type":"Objective","topic":"MONEY : FUNCTIONS OF MONEY","question":"The function of money do not include","images":[],"options":{"A":"store of value","B":"medium of exchange","C":"double coincidence of wants","D":"means of deferred payment"},"answer":"C","explanation":"The functions of money include serving as a medium of exchange, a store of value, and a unit of account. Money does not include the function of 'double coincidence of wants'. This term refers to the situation where the supplier of good A wants good B and the supplier of good B wants good A. This is a situation that money helps to avoid by providing a common medium of exchange.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>25","subject":"Commerce","year":"2018","type":"Objective","topic":"TRADE : DOCUMENT USED IN INTERNATIONAL TRADE","question":"A document of title of goods written by the ship owner,specifying that certain goods are being conveyed in the ship is a","images":[],"options":{"A":"bill of sale","B":"bill of sight","C":"bill of entry","D":"bill of lading"},"answer":"D","explanation":"A bill of lading is a document issued by a carrier (or their agent) to acknowledge receipt of cargo for shipment. In British English, the term relates to ship transport only, and in American English, to any type of transportation of goods. It serves three main purposes: it is a conclusive receipt, i.e., an acknowledgement that the goods have been loaded; and, which operates as a document of title to the goods, subject to the nemo dat quod non habet rule.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>26","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA","question":"Information advertising is aimed at","images":[],"options":{"A":"giving advice on the use of a product","B":"influencing customers to buy a product","C":"giving gifts to attract customers","D":"encouraging specific customers to buy a product"},"answer":"A","explanation":"Information advertising is a type of advertising that is used to inform consumers about a product or feature. This type of advertising is often used to introduce a new product or feature, or to promote a new use for an existing product. It is designed to educate the consumer and create a better understanding of the product.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>27","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"A cheap means of carrying bulky goods over a distance is by","images":[],"options":{"A":"rail","B":"road","C":"air","D":"pipeline"},"answer":"A","explanation":"Rail transport is known for being a cost-effective way to move large and heavy cargo over long distances. Trains can carry a significant amount of goods in a single trip, reducing the cost per unit of what's being transported.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>28","subject":"Commerce","year":"2018","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT","question":"A contract terminated by the occurrence of an event which makes performance impossible is discharged by","images":[],"options":{"A":"breach","B":"agreement","C":"frustration","D":"performance"},"answer":"C","explanation":"A contract is discharged by frustration when an event occurs that makes the performance of the contract impossible, illegal, or radically different from that contemplated by the parties at the time of the contract. This is not a breach, which is a failure to perform a contractual obligation, nor an agreement, which is a mutual decision to end the contract, nor performance, which is the completion of the contractual obligations.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>29","subject":"Commerce","year":"2018","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT","question":"An individual employed to act on behalf of another within a specific guideline is","images":[],"options":{"A":"a jobber","B":"an agent","C":"a broker","D":"a distributor"},"answer":"B","explanation":"An agent is an individual employed to act on behalf of another (the principal) within specific guidelines. The agent can make decisions and take actions that legally bind the principal. A jobber is a trader who buys goods from manufacturers and sells them to retailers. A broker is an intermediary who arranges transactions between a buyer and a seller, and a distributor is an entity that buys non-competing products or product lines and sells them direct to end users or customers.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>30","subject":"Commerce","year":"2018","type":"Objective","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"Which of the following is not a component of the marketing mix","images":[],"options":{"A":"price","B":"place","C":"population","D":"product"},"answer":"C","explanation":"The marketing mix, also known as the 4Ps of marketing, consists of Product, Price, Place (distribution), and Promotion. These are the controllable elements of a marketing program and are used to help a business reach its target market. Population is not a component of the marketing mix.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>31","subject":"Commerce","year":"2018","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"A method of buying in anticipation of price fluctuation in the commodity market is","images":[],"options":{"A":"speculation","B":"arbitrage","C":"contango","D":"hedging"},"answer":"A","explanation":"Speculation is the practice of engaging in risky financial transactions in an attempt to profit from fluctuations in the market value of a tradable good such as a financial instrument, rather than attempting to profit from the underlying financial attributes embodied in the instrument such as capital gains, interest, or dividends. This involves buying commodities in anticipation of price fluctuation.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>32","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION","question":"A shipping document detailing the charges for carrying a particular cargo for a specified voyage is","images":[],"options":{"A":"dock warrant","B":"freight note","C":"bill of lading","D":"mate's receipt"},"answer":"B","explanation":"A freight note is a shipping document that details the charges for carrying a particular cargo for a specified voyage. It is issued by a carrier and it specifies the type, quantity and destination of the goods being carried. A freight note also includes the charges, rate of freight and total freight chargeable.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>33","subject":"Commerce","year":"2018","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING","question":"Commercial agent who are authorized to keep goods untill they are sold are","images":[],"options":{"A":"factors","B":"distributors","C":"brokers","D":"auctioneers"},"answer":"A","explanation":"Factors are commercial agents who are authorized to keep goods until they are sold. They are entrusted with the possession of goods to be sold in their own name but on behalf of their principals. They have control over the goods and can sell them on credit, receive payment and even sue the buyer in their own name.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>34","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA","question":"An advertisement method whose objective is to convince customers to buy a product is","images":[],"options":{"A":"informative advertisement","B":"persuasive advertisement","C":"competitive advertisement","D":"mass advertisement"},"answer":"B","explanation":"Persuasive advertisement is a type of advertisement whose main goal is to convince customers to buy a product. It uses emotional appeal, logical arguments, and moral or ethical values to persuade customers to make a purchase.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>35","subject":"Commerce","year":"2018","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION","question":"A government legislation which ensures that quality goods and services are available to customers is","images":[],"options":{"A":"hire purchase Act","B":"copy right Act","C":"price control Act","D":"Standard organization Act"},"answer":"D","explanation":"The Standard Organization Act is a government legislation that ensures quality goods and services are available to customers. It sets and enforces standards for products and services to ensure they meet certain safety and quality requirements.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>36","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"A bank draft is a cheque drawn by a bank on","images":[],"options":{"A":"another bank","B":"itself","C":"creditors","D":"customers deposits"},"answer":"A","explanation":"A bank draft is a type of check where the payment is guaranteed to be available by the issuing bank. It is a check drawn by a bank on another bank, not on itself or on customers' deposits.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>37","subject":"Commerce","year":"2018","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"A company is quoted on the stock exchange when its share are","images":[],"options":{"A":"put under private placement","B":"not for sale to the public","C":"listed for sale on the stock exchange","D":"owned by the government"},"answer":"C","explanation":"A company is quoted on the stock exchange when its shares are listed for sale on the stock exchange. This means that the company's shares are publicly traded and anyone can buy them. The stock exchange is a marketplace where buyers and sellers meet to trade stocks.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>38","subject":"Commerce","year":"2018","type":"Objective","topic":"TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.","question":"Which of the following functions is not performed by the export promotion council?","images":[],"options":{"A":"prevention of importation of harmful goods","B":"provision of credit facilities to exporters","C":"provision of technical advice to exporters","D":"creation of export free zones"},"answer":"A","explanation":"The function of the export promotion council is to promote and support export activities. This includes providing credit facilities to exporters, providing technical advice, and creating export free zones. However, preventing the importation of harmful goods is not a function of the export promotion council. This function is typically performed by customs and other regulatory bodies.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>39","subject":"Commerce","year":"2018","type":"Objective","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"Activities undertaken to create awareness of a product by giving out samples or gifts is","images":[],"options":{"A":"marketing mix","B":"marketing concept","C":"window display","D":"sales promotion"},"answer":"D","explanation":"Sales promotion is a marketing strategy where a company tries to get more customers by offering them special deals, discounts, or incentives. This can include giving out samples or gifts to create awareness of a product. The other options, marketing mix, marketing concept, and window display, are all different aspects of marketing but they do not specifically refer to the activity of giving out samples or gifts to promote a product.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>40","subject":"Commerce","year":"2018","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES","question":"An advantage of privatizing a firm is that it","images":[],"options":{"A":"become more efficient","B":"sells good at low prices","C":"employ more workers","D":"attracts more customers"},"answer":"A","explanation":"Privatization often leads to increased efficiency due to the profit motive, which drives firms to cut costs and innovate. Privatization eliminates bureaucratic red tape that can slow down decision making, and allows firms to respond more quickly to market forces.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>41","subject":"Commerce","year":"2018","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"The transformation of authority by a superior officer to his subordinate in an organization","images":[],"options":{"A":"controlling","B":"decentralization","C":"delegation","D":"directing"},"answer":"C","explanation":"Delegation is the process of assigning responsibility or authority to another person to carry out specific activities. It allows a person to move from what they've been doing to what they should be doing. It increases efficiency and allows for better management in an organization.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>42","subject":"Commerce","year":"2018","type":"Objective","topic":"ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE","question":"The provision of scholarships by a firm to needy students is part of its","images":[],"options":{"A":"political responsibility","B":"economic responsibility","C":"social responsibility","D":"legal responsibility"},"answer":"C","explanation":"Providing scholarships to needy students is part of a firm's social responsibility. Social responsibility is an ethical framework that suggests that an entity, be it an organization or individual, has an obligation to act for the benefit of society at large. It is a duty every individual or organization has to perform so as to maintain a balance between the economy and the ecosystem.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>43","subject":"Commerce","year":"2018","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"How many countries form ECOWAS","images":[],"options":{"A":"17","B":"16","C":"15","D":"14"},"answer":"C","explanation":"The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. It was founded on May 28, 1975, with the signing of the Treaty of Lagos. Its mission is to promote economic integration across the region.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>44","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"Which of the following is a modern means of communication?","images":[],"options":{"A":"Grape vine","B":"E-mail","C":"Whistles","D":"Town crier"},"answer":"B","explanation":"E-mail is a modern means of communication. It is a method of exchanging messages between people using electronic devices. Invented by Ray Tomlinson, email first entered limited use in the 1960s and by the mid-1970s had taken the form now recognized as email.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2018>45","subject":"Commerce","year":"2018","type":"Objective","topic":"STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS","question":"A system of issuing new shares to selected investors instead of the general public is","images":[],"options":{"A":"public offer","B":"issue by tender","C":"offer for sale","D":"private placement"},"answer":"D","explanation":"Private placement is a method of issuing new shares to selected investors instead of the general public. It is a funding round of securities which are sold not through a public offering, but rather through a private offering, mostly to a small number of chosen investors.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>46","subject":"Commerce","year":"2018","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"One of the aims of the European Union is to","images":[],"options":{"A":"ease trade among members countries","B":"enhance better trade with Africa","C":"enhance free trade with America","D":"offer financial assistance to poor countries"},"answer":"A","explanation":"The European Union (EU) is a political and economic union of 27 member states that are located primarily in Europe. One of its main aims is to promote peace, its values and the well-being of its citizens. It also aims to offer freedom, security and justice without internal borders. An important aspect of this is the ease of trade among member countries. This is achieved through a single market which allows goods, services, money and people to move freely.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>47","subject":"Commerce","year":"2018","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES","question":"The purpose of commercialization is to","images":[],"options":{"A":"encourage the participation of private sector","B":"make state-owned firms more efficient","C":"encourage the flow of foreign capital","D":"enable state-owned firms pay tax"},"answer":"B","explanation":"Commercialization is the process of introducing a new product or production method into commerce\u2014making it available on the market. The purpose of commercialization is to make state-owned firms more efficient. This is achieved by introducing competition, which forces the firms to improve their efficiency in order to survive. It also often involves the participation of the private sector, but the main aim is to improve efficiency.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>48","subject":"Commerce","year":"2018","type":"Objective","topic":"TRADE : DOCUMENT USED IN INTERNATIONAL TRADE","question":"The time allowed for loading and unloading a ship at the harbour is","images":[],"options":{"A":"demurrage","B":"tenure","C":"lay days","D":"dead freight"},"answer":"C","explanation":"In shipping, lay days are the days allowed by the charterer for loading and unloading the cargo. If the ship is detained beyond this period, demurrage is charged. Therefore, the time allowed for loading and unloading a ship at the harbour is referred to as lay days.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2018>49","subject":"Commerce","year":"2018","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Inter-bank indebtedness is settled at the","images":[],"options":{"A":"clearing house","B":"money market","C":"discount house","D":"stock exchange"},"answer":"A","explanation":"Inter-bank indebtedness is settled at the clearing house. A clearing house is a financial institution formed to facilitate the exchange (i.e., clearance) of payments, securities, or derivatives transactions. The clearing house stands between two clearing firms (also known as member firms or clearing participants) and its purpose is to reduce the risk of one (or more) clearing firm failing to honor its trade settlement obligations.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2018>50","subject":"Commerce","year":"2018","type":"Objective","topic":"ELEMENT OF MARKETING : THE MARKETING CONCEPT","question":"The concern of a marketing manager whose company has adopted the marketing concept is to","images":[],"options":{"A":"recruit more salesmen","B":"make maximum profit","C":"identify and satisfy customers needs","D":"maintain the company's share of the market"},"answer":"C","explanation":"The concern of a marketing manager whose company has adopted the marketing concept is to identify and satisfy customers needs. The marketing concept is a business philosophy that holds that the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value to its chosen target markets.","marks":"1","difficulty":"2"}];